import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";

const Projects = () => {
  const navigate = useNavigate();
  const [proposals, setProposals]     = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [submitting, setSubmitting]   = useState(false);
  const [modal, setModal]             = useState(null);
  const [form, setForm]               = useState({ description: "", github_link: "", live_link: "" });
  const [error, setError]             = useState("");
  const [success, setSuccess]         = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        const [propRes, subRes] = await Promise.all([
          API.get("/proposals/my"),
          API.get("/submissions/my"),
        ]);
        setProposals((propRes.data || []).filter(p => p.status === "accepted"));
        setSubmissions(subRes.data || []);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  // Match by project_id
  const getSubmission = (projectId) =>
    submissions.find(s => s.project_id === projectId);

  const openModal = (project) => {
    const sub = getSubmission(project.project_id);
    setForm({
      description: sub?.description || "",
      github_link: sub?.github_link || "",
      live_link:   sub?.live_link   || "",
    });
    setError("");
    setModal(project);
  };

  const handleSubmit = async () => {
    if (!form.description) { setError("Description is required!"); return; }
    setSubmitting(true);
    try {
      await API.post("/submissions", {
        project_id:  modal.project_id,
        description: form.description,
        github_link: form.github_link,
        live_link:   form.live_link,
      });
      const res = await API.get("/submissions/my");
      setSubmissions(res.data || []);
      setSuccess("Project submitted successfully!");
      setTimeout(() => { setSuccess(""); setModal(null); }, 1500);
    } catch (err) {
      setError(err.response?.data?.message || "Submission failed");
    }
    setSubmitting(false);
  };

  // ✅ Match DB enum: 'submitted', 'approved', 'revision'
  const statusStyle = (s) => {
    if (s === "approved")  return "bg-green-100 text-green-700 border-green-200";
    if (s === "revision")  return "bg-orange-100 text-orange-600 border-orange-200";
    return "bg-blue-100 text-blue-700 border-blue-200";  // submitted
  };

  const statusIcon = (s) => {
    if (s === "approved") return "✅";
    if (s === "revision") return "🔄";
    return "📤";
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-4xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">My Projects</h1>
        <p className="text-gray-500 text-sm mb-6">Submit your completed work for client review</p>

        {success && (
          <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-5 text-sm">
            ✅ {success}
          </div>
        )}

        {proposals.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
            <div className="text-5xl mb-3">📭</div>
            <p className="text-gray-500 mb-2">No accepted projects yet.</p>
            <p className="text-gray-400 text-sm mb-5">You need to get hired first before submitting work.</p>
            <button onClick={() => navigate("/freelancer/find-projects")}
              className="bg-teal-600 text-white px-5 py-2 rounded-lg text-sm font-medium hover:bg-teal-700 transition">
              Find Projects
            </button>
          </div>
        ) : (
          <div className="space-y-4">
            {proposals.map((p) => {
              const sub = getSubmission(p.project_id);
              return (
                <div key={p.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">

                  {/* TOP ROW */}
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex-1 min-w-0">
                      <h3 className="font-bold text-gray-800 text-lg">{p.project_title}</h3>
                      <div className="flex gap-5 text-sm text-gray-500 mt-1">
                        <span>Budget: <strong className="text-gray-700">₹{p.project_budget || p.budget}</strong></span>
                        <span>Your Bid: <strong className="text-teal-600">₹{p.bid}</strong></span>
                      </div>
                    </div>

                    {/* ACTION BUTTON */}
                    <div className="ml-4 flex-shrink-0">
                      {!sub ? (
                        <button onClick={() => openModal(p)}
                          className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
                          🚀 Submit Work
                        </button>
                      ) : sub.status === "revision" ? (
                        <button onClick={() => openModal(p)}
                          className="bg-orange-500 hover:bg-orange-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
                          🔄 Resubmit
                        </button>
                      ) : (
                        <span className="text-gray-400 text-sm font-medium">Submitted ✓</span>
                      )}
                    </div>
                  </div>

                  {/* SUBMISSION DETAILS */}
                  {sub && (
                    <div className="mt-3 p-4 bg-gray-50 rounded-lg border border-gray-200">
                      <div className="flex items-center gap-2 mb-2">
                        <span className="text-sm font-medium text-gray-600">Status:</span>
                        <span className={`px-3 py-0.5 rounded-full text-xs font-semibold capitalize border ${statusStyle(sub.status)}`}>
                          {statusIcon(sub.status)} {sub.status}
                        </span>
                      </div>

                      {sub.description && (
                        <p className="text-gray-600 text-sm mb-3">{sub.description}</p>
                      )}

                      <div className="flex gap-4 text-sm">
                        {sub.github_link && (
                          <a href={sub.github_link} target="_blank" rel="noreferrer"
                            className="text-blue-500 hover:underline flex items-center gap-1">
                            🔗 GitHub
                          </a>
                        )}
                        {sub.live_link && (
                          <a href={sub.live_link} target="_blank" rel="noreferrer"
                            className="text-green-500 hover:underline flex items-center gap-1">
                            🌐 Live Demo
                          </a>
                        )}
                      </div>

                      {/* Feedback from client */}
                      {sub.feedback && (
                        <div className="mt-3 bg-yellow-50 border border-yellow-200 rounded-lg p-3">
                          <p className="text-yellow-700 text-sm font-medium mb-1">💬 Client Feedback:</p>
                          <p className="text-yellow-600 text-sm">{sub.feedback}</p>
                        </div>
                      )}

                      {sub.status === "revision" && (
                        <div className="mt-3 bg-orange-50 border border-orange-200 rounded-lg p-3">
                          <p className="text-orange-600 text-sm font-medium">📝 Revision requested — please resubmit your work.</p>
                        </div>
                      )}
                      {sub.status === "approved" && (
                        <div className="mt-3 bg-green-50 border border-green-200 rounded-lg p-3">
                          <p className="text-green-600 text-sm font-medium">✅ Project Approved! Great work!</p>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ===== SUBMIT MODAL ===== */}
      {modal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 px-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg p-6">
            {success ? (
              <div className="text-center py-8">
                <div className="text-5xl mb-3">🎉</div>
                <p className="text-green-600 font-bold text-lg">{success}</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-start mb-5">
                  <div>
                    <h2 className="text-lg font-bold text-gray-800">Submit Your Work</h2>
                    <p className="text-sm text-gray-500">{modal.project_title}</p>
                  </div>
                  <button onClick={() => setModal(null)}
                    className="text-gray-400 hover:text-gray-600 text-xl font-bold">✕</button>
                </div>

                {error && (
                  <div className="mb-4 bg-red-50 text-red-600 px-4 py-2 rounded-lg text-sm border border-red-200">{error}</div>
                )}

                <div className="mb-4">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Work Description <span className="text-red-400">*</span>
                  </label>
                  <textarea value={form.description}
                    onChange={e => setForm({ ...form, description: e.target.value })}
                    rows={3} placeholder="Describe what you built..."
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none" />
                </div>

                <div className="mb-4">
                  <label className="block text-sm font-medium text-gray-700 mb-1">🔗 GitHub Repository</label>
                  <input type="url" value={form.github_link}
                    onChange={e => setForm({ ...form, github_link: e.target.value })}
                    placeholder="https://github.com/username/repo"
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>

                <div className="mb-6">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    🌐 Live Demo <span className="text-gray-400">(optional)</span>
                  </label>
                  <input type="url" value={form.live_link}
                    onChange={e => setForm({ ...form, live_link: e.target.value })}
                    placeholder="https://yourproject.vercel.app"
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>

                <div className="flex gap-3">
                  <button onClick={handleSubmit} disabled={submitting}
                    className="flex-1 bg-teal-600 hover:bg-teal-700 text-white py-2 rounded-lg text-sm font-semibold transition disabled:opacity-50">
                    {submitting ? "Submitting..." : "Submit Project"}
                  </button>
                  <button onClick={() => setModal(null)}
                    className="px-5 py-2 rounded-lg text-sm font-medium border border-gray-300 text-gray-600 hover:bg-gray-50 transition">
                    Cancel
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Projects;
